UPDATE coaching.exercise SET
  name = 'Wrist / Forearm Capacity Series',
  description = 'The athlete performs a small series of controlled wrist and forearm drills, usually 2–4 selected movements per session. The coach chooses based on the athlete''s sport demand and symptoms.',
  card_summary = 'Accessory series for wrist flexion, wrist extension, pronation/supination, grip, and hand-support tolerance.',
  coach_language = 'Use as the default wrist/forearm capacity card for gymnastics, tumbling, ninja, climbing, crawling, handstands, bars, rings, and grip work.',
  athlete_language = 'Move the wrist slowly, control the weight, build both sides of the forearm, and stop if pain gets sharp.',
  movement_family = 'Tissue capacity: isometric, eccentric & accessory strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'tissue_capacity_isometric_eccentric_accessory',
  primary_order_slot = 'wrist_forearm_capacity',
  default_sets = 2,
  default_reps = 12,
  default_work_seconds = 20,
  default_rest_seconds = 30,
  est_seconds_per_set = 45,
  movement_requirements = '{"primary_joint_actions":["wrist_flexion","wrist_extension","forearm_pronation","forearm_supination","grip"],"primary_tissues":["forearm_flexors","forearm_extensors","finger_flexors"],"breathing_demand":"nasal","balance_demand":"stable","impact_level":0,"prerequisites":[],"setup_requirements":["Secure band or strap anchor for Spanish squat setups","Bench or box support for Copenhagen plank short lever","Wall or tib bar for tibialis raise progressions","Bench or calf-raise machine for seated soleus raise","Light dumbbell, band, rice bucket, or wrist roller for wrist/forearm series"]}'::jsonb,
  coaching_execution = '{"movement_description":"Coach selects 2–4 controlled wrist/forearm drills from the series options; athlete performs slow reps or short holds with forearm supported and pain-free range.","series_options":["Wrist extension curl","Wrist flexion curl","Pronation / supination with light dumbbell or hammer","Radial / ulnar deviation","Wrist roller","Rice bucket open / close / rotate","Finger extension band opens","Grip squeeze or towel squeeze","Quadruped wrist rockers","Palm lift / fingertip support progression"],"setup":["Choose 2-4 drills based on athlete need.","Use light load.","Forearm supported for isolation drills.","Move slowly through pain-free range.","Stop before form or symptoms degrade."],"execution_steps":["Control the full range.","Pause briefly at end range if assigned.","Lower slowly.","Avoid jerky reps.","Train both sides of the forearm.","Track symptom response after session."],"breathing_cues":["Breathe normally — avoid jaw/neck tension during grip work."],"coach_cues":["Slow and controlled.","Small joints, small load.","Train both directions.","No sharp pain.","Stop before grip fails."],"athlete_cues":["Control it.","Light weight.","Both sides.","No sharp pain."],"common_faults":["Load too heavy.","Jerky wrist reps.","Only training wrist flexors and ignoring extensors.","Working to grip failure before skill work.","Ignoring radial-side wrist pain.","Too much volume after hanging/climbing."],"stop_signs":["Sharp wrist pain.","Numbness or tingling.","Pain with gripping that worsens.","Thumb-side wrist pain during grip or deviation.","Loss of hand support tolerance."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Dead Hang / Active Hang","Ring Support Hold","Handstand Prep","Rope Climb Progression","Ninja Grip Work"],"pairs_well_after":["Wrist Rockers","Palm Pulses","Forearm Soft Tissue Prep","Scapular Push-Up"],"good_for_sessions":["capacity_tissue","tissue_capacity_accessory","injury_prevention"],"avoid_before":["Max grip work before ninja obstacles","Hard wrist extension work before handstand/tumbling if it causes fatigue","High-volume forearm work after rope climbs"],"avoid_after":[],"do_not_use_when":["Sharp wrist pain","Numbness or tingling","Grip pain worsening with reps","Recent wrist injury without clearance","Hand support becomes painful after series"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Hinge Health wrist strengthening drills","Healthline forearm exercise and grip strength guidance","PureGym wrist-strengthening and stretching balance across the week"],"internal_notes":["daily_ok true — validator should warn on wrist/grip fatigue before tumbling, handstand, ninja, rings, or bar work."]}'::jsonb,
  updated_at = now()
WHERE slug = 'wrist-forearm-capacity-series';

UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'wrist_forearm_capacity',
  order_index = pos.order_index,
  fit_weight = 5,
  freshness_required = FALSE,
  fatigue_sensitivity = 3,
  fatigue_cost = 2,
  technical_complexity = 3,
  impact_level = 0,
  intensity_ceiling = 'moderate',
  notes = 'Can be frequent at low intensity. Hard grip/forearm work should not be placed before ninja, bars, rings, or tumbling if it compromises hand support. Supervision: optional.'
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'capacity'
JOIN coaching.phase_order_slot pos ON pos.key = 'wrist_forearm_capacity' AND pos.phase_id = sp.id
WHERE p.exercise_id = e.id AND p.phase_id = sp.id AND e.slug = 'wrist-forearm-capacity-series';

UPDATE coaching.exercise_dosage_profile d SET
  volume_unit = 'reps_or_seconds',
  default_sets = 2,
  default_reps = 12,
  default_work_seconds = 20,
  default_rest_seconds = 30,
  tempo = 'slow controlled reps',
  est_seconds_per_set = 45,
  default_rpe_min = 2,
  default_rpe_max = 6,
  session_volume_min = 4,
  session_volume_max = 24
FROM coaching.exercise e
WHERE d.exercise_id = e.id AND d.profile_name = 'Default' AND e.slug = 'wrist-forearm-capacity-series';

UPDATE coaching.exercise_regimen_rule r SET
  can_be_daily = TRUE,
  weekly_max_frequency = CASE WHEN TRUE THEN 7 ELSE r.weekly_max_frequency END
FROM coaching.exercise e
WHERE r.exercise_id = e.id AND e.slug = 'wrist-forearm-capacity-series';

-- Refresh weighted taxonomy tags for tissue Capacity cards
DELETE FROM coaching.exercise_tag t
USING coaching.exercise e
WHERE t.exercise_id = e.id
  AND e.slug IN ('spanish-squat-isometric', 'split-squat-isometric-hold', 'copenhagen-plank-short-lever', 'tibialis-raise', 'seated-soleus-raise-bent-knee-calf-raise', 'wrist-forearm-capacity-series')
  AND t.facet_type IN ('tenet', 'methodology', 'physiology', 'pattern', 'equipment', 'body_region');

