-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('spanish-squat-isometric', 'The Spanish squat is an isometric squat variation that can create strong quadriceps demand while the band or strap supports the athlete''s body position. Research on the Basas Spanish Squat found that it can be a challenging quadriceps exercise even though it is isometric, and it is commonly discussed in patellar tendinopathy and anterior-knee-pain contexts.', 'Belongs in quad_tendon_capacity (461) — default Capacity quad/patellar tendon isometric after main squat work.', 'quad_tendon_capacity after Output and main Capacity squat work; This cluster usually lives after Output and main Capacity lifts unless used as a low-intensity primer, readiness tool, or rehab-style accessory.', 'Capacity builds tissue, tendon, and accessory strength with controlled positions, meaningful time-under-tension, and full rest — not Prepare activation fluff, Fitness burnout circuits, or Control rehab-style holds at low intensity. Do not use unsafe band anchors, passive hanging into the strap, or aggressive depth/hold progressions that irritate anterior knee symptoms.', 'Regress depth or hold time before reducing posture standard; hypermobility athletes need active knee/hip control — avoid hanging passively into the band.'),
  ('split-squat-isometric-hold', 'Split-stance isometrics build positional strength and tissue tolerance without the coordination demand of stepping in and out of lunges. Isometrics are often useful when the goal is to hold a joint angle, build position tolerance, and control alignment before adding dynamic reps.', 'Belongs in split_stance_isometric (462) — unilateral split-stance Capacity isometric after bilateral squat base.', 'split_stance_isometric after Output and main Capacity unilateral work; This cluster usually lives after Output and main Capacity lifts unless used as a low-intensity primer, readiness tool, or rehab-style accessory.', 'Capacity builds tissue, tendon, and accessory strength with controlled positions, meaningful time-under-tension, and full rest — not Prepare activation fluff, Fitness burnout circuits, or Control rehab-style holds at low intensity. Do not allow knee valgus, breath-holding, or depth beyond control — not a lunge burnout circuit.', 'Regress to supported hold or shallow depth before reducing alignment standard; hypermobility athletes need active foot/knee/hip tension — avoid sinking passively.'),
  ('copenhagen-plank-short-lever', 'The Copenhagen plank trains the adductors and lateral trunk, which are important for cutting, sprinting, lateral movement, and groin durability. A 2025 review describes the Copenhagen Adduction Exercise as one of the most studied eccentric exercises in groin-injury-prevention contexts, and E3 Rehab describes the short-lever version as lifting the hips until the body forms a straight line with the knee/thigh supported.', 'Belongs in adductor_capacity (463) — default short-lever Copenhagen before long-lever progressions.', 'adductor_capacity after Output and main Capacity lower-body work; default Copenhagen regression before long lever; This cluster usually lives after Output and main Capacity lifts unless used as a low-intensity primer, readiness tool, or rehab-style accessory.', 'Capacity builds tissue, tendon, and accessory strength with controlled positions, meaningful time-under-tension, and full rest — not Prepare activation fluff, Fitness burnout circuits, or Control rehab-style holds at low intensity. Do not use long lever too soon, ignore groin pain, or stack holds with short rest as a burnout circuit.', 'Regress to side plank or adductor squeeze before long lever; hypermobility athletes need stacked pelvis/ribs — avoid end-range hip strain.'),
  ('tibialis-raise', 'Tibialis raises strengthen the anterior tibialis, the muscle group responsible for dorsiflexing the ankle and helping control foot position. Hinge Health describes tibialis raises as a strengthening exercise for shin, ankle, and foot strength, often performed by leaning against a wall and lifting the toes off the ground; a 2023 study also reported that tibialis anterior resistance training can improve tibialis anterior strength and ankle/foot function.', 'Belongs in shin_capacity (464) — anterior shin Capacity accessory; can be used frequently at low-to-moderate load.', 'shin_capacity after Output and main Capacity work; daily-ok at low-to-moderate load; This cluster usually lives after Output and main Capacity lifts unless used as a low-intensity primer, readiness tool, or rehab-style accessory.', 'Capacity builds tissue, tendon, and accessory strength with controlled positions, meaningful time-under-tension, and full rest — not Prepare activation fluff, Fitness burnout circuits, or Control rehab-style holds at low intensity. Do not ignore cramping, use aggressive wall angle, or stack high volume before sprint/jump Output when shins are irritated.', 'Regress to seated toe lifts or closer wall angle before adding tib bar load; hypermobility athletes need controlled range — avoid aggressive end-range snapping.'),
  ('seated-soleus-raise-bent-knee-calf-raise', 'Bent-knee calf raises bias the soleus because the knee-flexed position reduces gastrocnemius contribution and increases the relative role of the deeper calf muscle. TreatMyAchilles describes bent-knee calf raises as an effective way to target the soleus and the Achilles tendon portion associated with it, and RehabHero describes seated calf raises as specifically targeting the soleus with forefoot elevation and load placed near the knee.', 'Belongs in soleus_capacity (465) — default Capacity soleus/Achilles bent-knee calf raise.', 'soleus_capacity after Output and main Capacity work; default soleus/Achilles Capacity card; This cluster usually lives after Output and main Capacity lifts unless used as a low-intensity primer, readiness tool, or rehab-style accessory.', 'Capacity builds tissue, tendon, and accessory strength with controlled positions, meaningful time-under-tension, and full rest — not Prepare activation fluff, Fitness burnout circuits, or Control rehab-style holds at low intensity. Do not bounce reps, progress load too fast with Achilles symptoms, or stack hard soleus work before high-volume pogos or sprints.', 'Regress to bodyweight seated raises before loading; hypermobility athletes need controlled top and bottom range — avoid collapsing into end range.'),
  ('wrist-forearm-capacity-series', 'Wrist and forearm capacity matters because gymnasts, tumblers, ninja athletes, and climbers repeatedly load the hands through gripping, hanging, crawling, hand support, and impact positions. Hinge Health lists wrist strengthening drills as useful for improving mobility, reducing pain, and supporting hand/wrist function, while grip-strength research and reviews emphasize that grip can be a limiting factor in strength and sport performance. A good series should cover both sides of the forearm: wrist flexion, wrist extension, pronation, supination, radial/ulnar deviation, finger flexor/grip work, and hand-support tolerance.', 'Belongs in wrist_forearm_capacity (466) — default Capacity wrist/forearm/grip accessory series; can be frequent at low intensity.', 'wrist_forearm_capacity after Output and main Capacity work; choose 2–4 drills per session; This cluster usually lives after Output and main Capacity lifts unless used as a low-intensity primer, readiness tool, or rehab-style accessory.', 'Capacity builds tissue, tendon, and accessory strength with controlled positions, meaningful time-under-tension, and full rest — not Prepare activation fluff, Fitness burnout circuits, or Control rehab-style holds at low intensity. Do not load too heavy, train flexors only, or work to grip failure before ninja, bars, rings, or tumbling skill work.', 'Choose 2–4 drills per session with light load; hypermobility athletes need active control and small loads — avoid end-range hanging.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Tissue Capacity cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'capacity_tissue_readiness',
  NULL,
  'Tissue Capacity without irritating bottleneck tissues',
  'Tissue Capacity builds quad, split-stance, adductor, shin, soleus, and wrist/forearm reserve with controlled positions and meaningful time-under-tension — not primer fluff or burnout circuits.',
  'Tissue cluster: Spanish Squat Isometric, Split Squat Isometric Hold, Copenhagen Plank — Short Lever, Tibialis Raise, Seated Soleus Raise / Bent-Knee Calf Raise, and Wrist / Forearm Capacity Series.',
  'These drills keep athletes available for sprinting, jumping, landing, cutting, tumbling, and hand-support work. Poor placement or aggressive progression irritates tendons and joints instead of building durable capacity.',
  'Place after Output and main Capacity lifts unless used as a low-intensity primer; monitor symptoms on every hold; progress hold time, depth, or load slowly; keep wrist/grip work conservative before bars, rings, ninja, or tumbling.',
  'Do not use unsafe band anchors, ignore groin or anterior knee pain, stack hard calf or shin work before elastic Output, or fatigue wrists/grip before hand-support skill.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
